#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int turns = 0;
        while (1) {
            int allNonNegative = 1;
            for (int i = 0; i < N; i++) {
                if (A[i] < 0) {
                    allNonNegative = 0;
                    break;
                }
            }
            if (allNonNegative) break;
            int minIndex = 0;
            for (int i = 1; i < N; i++) {
                if (A[i] < A[minIndex]) {
                    minIndex = i;
                }
            }
            int prev = (minIndex - 1 + N) % N;
            int next = (minIndex + 1) % N;
            A[prev] += A[minIndex];
            A[next] += A[minIndex];
            A[minIndex] = -A[minIndex];
            turns++;
        }
        printf("%d\n", turns);
    }
    return 0;
}

