        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int turns = 0;
            while (true) {
                boolean allNonNegative = true;
                for (int i = 0; i < N; i++) {
                    if (A[i] < 0) {
                        allNonNegative = false;
                        break;
                    }
                }
                if (allNonNegative) break;
                int minIndex = 0;
                for (int i = 1; i < N; i++) {
                    if (A[i] < A[minIndex]) {
                        minIndex = i;
                    }
                }
                int prev = (minIndex - 1 + N) % N;
                int next = (minIndex + 1) % N;
                A[prev] += A[minIndex];
                A[next] += A[minIndex];
